<script setup lang="ts">
import { CloudIcon, PawPrintIcon } from '@lucide/vue'
import { computed } from 'vue'

interface ProviderIdentity {
  id?: string
  name?: string
  type?: string
  baseUrl?: string
}

type ProviderBrand = 'anthropic' | 'ollama' | 'omniinfer' | 'openai' | 'unknown'

const props = defineProps<{
  provider: ProviderIdentity
}>()

const brand = computed<ProviderBrand>(() => {
  const identity = [
    props.provider.id,
    props.provider.name,
    props.provider.type,
    props.provider.baseUrl,
  ]
    .filter(Boolean)
    .join(' ')
    .toLowerCase()

  if (identity.includes('omniinfer')) return 'omniinfer'
  if (identity.includes('ollama')) return 'ollama'
  if (identity.includes('anthropic') || identity.includes('claude')) return 'anthropic'
  if (identity.includes('openai') || identity.includes('chatgpt') || identity.includes('codex')) {
    return 'openai'
  }

  return 'unknown'
})
</script>

